class Solution:
    def equalFrequency(self, word: str) -> bool:
        for i in range(len(word)):
            freq = {}
            for j in range(len(word)):
                if j != i:
                    freq[word[j]] = freq.get(word[j], 0) + 1
            if len(set(freq.values())) == 1:
                return True
        return False
